 obsidian_count="$(find "$TEST_HOME/obsidian/Claude/Sessions" -maxdepth 1 -name '*.md' 2>/dev/null | wc -l | tr -d ' ')"
 [ "$obsidian_count" -ge 1 ] || {
     echo "FAIL shutdown hook did not synthesize an Obsidian session note" >&2
     exit 1
